        <div style="text-align:center;color:var(--muted);font-size:13px;padding:16px">Loading schedule...</div>
      </div>
      <button class="btn btn-accent" style="margin-top:12px" onclick="saveAvailability()">💾 Save Schedule</button>
    </div>

    <!-- MY ZONES -->
    <div class="card" id="myZonesCard">
      <div style="font-size:14px;font-weight:700;margin-bottom:4px">🗾 My Service Zones</div>
