<div class="toast" id="toast"></div>





<script>


var _lastJobCount = -1;

async function updateDashboard() {
  if (!engData) return;
  document.getElementById('dashName').textContent = engData.name;
  highlightStatus(engData.status || 'offline');

  var res = await api('GET', '/engineer/jobs');
  if (!res.success) return;

  var jobs = Array.isArray(res.data) ? res.data : (res.jobs || []);
  // Alert engineer when new job offers arrive during polling
  var newOffers = jobs.filter(function(j){ return j.status === 'pending'; }).length;
  if (_lastJobCount >= 0 && newOffers > _lastJobCount) {
    toast('🔔 New job offer received!');
    var badge = document.getElementById('notifBadge');
    if (badge) { badge.textContent = '!'; badge.style.display = 'block'; }
  }
  _lastJobCount = newOffers;
  var offered = jobs.filter(j => j.status === 'pending' || j.status === 'assigned').length;
  var active  = jobs.filter(j => ['accepted','on_the_way','arrived','working'].includes(j.status)).length;
  document.getElementById('st-today').textContent   = jobs.length;
  document.getElementById('st-pending').textContent = offered;
  document.getElementById('st-done').textContent    = active;

  var list = document.getElementById('activeJobsList');
  if (!jobs.length) {
    list.innerHTML = '<div style="text-align:center;padding:32px;color:var(--hint)">No active jobs</div>';
    return;
  }

  list.innerHTML = jobs.map(j => {
    var isOffer     = (j.status === 'pending' || j.status === 'assigned');
    var isRevisit   = j.status === 'revisit_scheduled';
    var isQuotation = ['awaiting_quotation','quotation_sent','quotation_approved'].includes(j.status);
    var isPickup    = ['pickup_requested','device_picked'].includes(j.status);
    var cardClass = j.priority === 'urgent' ? 'card-urgent'
      : j.status === 'working' ? 'card-active'
      : isOffer ? 'card-offer'
      : isRevisit ? 'card-revisit'
      : isQuotation || isPickup ? 'card-pending-action' : '';
    return `
    <div class="card ${cardClass}" onclick="openJob(${j.id})" style="${isOffer?'border-left:3px solid var(--amber)':''}">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px">
        <div>
          <div style="font-weight:700;font-size:15px">${j.service_name || j.service_type || 'Service'}</div>
          <div style="font-size:12px;font-family:monospace;color:var(--hint)">${j.job_number}</div>
        </div>
        <span class="badge ${isOffer?'b-pending':isRevisit?'b-assigned':isQuotation||isPickup?'b-pending':'b-'+j.status}">${isOffer?'🔔 New Job':isRevisit?'📅 Revisit Scheduled':isQuotation?'📋 Quotation':isPickup?'🔧 Pickup':j.status.replace(/_/g,' ')}</span>
      </div>
      <div style="font-size:13px;color:var(--muted);margin-bottom:4px">👤 ${j.customer_name} · 📞 ${j.customer_phone}</div>
      <div style="font-size:12px;color:var(--hint);margin-bottom:6px">📍 ${j.address}</div>
      ${j.scheduled_date ? `<div style="font-size:12px;font-weight:700;color:#F59E0B;margin-bottom:6px;background:rgba(245,158,11,.1);border-radius:8px;padding:5px 10px;display:inline-block">📅 ${j.scheduled_date}${j.slot_label ? ' · '+j.slot_label : ''}</div>` : ''}
      <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:4px">
        ${j.distance_km ? `<span style="font-size:11px;background:rgba(79,110,247,.1);color:var(--accent);padding:3px 8px;border-radius:20px;font-weight:600">📍 ${j.distance_km} km away</span>` : ''}
        ${j.avg_rating > 0 ? `<span style="font-size:11px;background:rgba(245,158,11,.1);color:#F59E0B;padding:3px 8px;border-radius:20px;font-weight:600">⭐ ${parseFloat(j.avg_rating||0).toFixed(1)} rating</span>` : ''}
        ${j.completed_jobs > 0 ? `<span style="font-size:11px;background:rgba(34,197,94,.1);color:var(--green);padding:3px 8px;border-radius:20px;font-weight:600">✅ ${j.completed_jobs} done</span>` : ''}
        ${j.notification_type === 'nearby_fallback' || j.outside_zone ? `<span style="font-size:11px;background:rgba(239,68,68,.12);color:#EF4444;padding:3px 8px;border-radius:20px;font-weight:600;border:1px solid rgba(239,68,68,.25)">📍 Outside Your Zone</span>` : (j.notification_type === 'zone_job' ? `<span style="font-size:11px;background:rgba(79,110,247,.12);color:var(--accent);padding:3px 8px;border-radius:20px;font-weight:600;border:1px solid rgba(79,110,247,.25)">🗾 Your Zone</span>` : '')}
      </div>
      ${(j.display_amount > 0 || parseFloat(j.visit_charge||0) > 0) ? `
      <div style="background:rgba(34,197,94,.08);border:1px solid rgba(34,197,94,.2);border-radius:10px;padding:10px;margin-top:8px">
        <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:4px">
          <span style="color:var(--muted)">Service Charge</span>
          <span>₹${parseFloat(j.amount||0).toLocaleString('en-IN',{minimumFractionDigits:2})}</span>
        </div>
        ${parseFloat(j.visit_charge||0)>0 ? `<div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:4px">
          <span style="color:var(--muted)">Visit Charge</span>
          <span>₹${parseFloat(j.visit_charge||0).toLocaleString('en-IN',{minimumFractionDigits:2})}</span>
        </div>` : ''}
        <div style="display:flex;justify-content:space-between;font-size:14px;font-weight:800;border-top:1px solid rgba(34,197,94,.2);padding-top:6px;margin-top:2px">
          <span style="color:var(--green)">Total</span>
          <span style="color:var(--green)">₹${Number(j.display_amount).toLocaleString('en-IN',{minimumFractionDigits:2})}</span>
        </div>
      </div>` : ''}
      <div class="job-actions">
        ${isOffer ? `<button class="btn btn-green btn-sm" onclick="event.stopPropagation();acceptJob(${j.id})">✓ Accept</button>` : ''}
        ${isOffer ? `<button class="btn btn-sm" style="background:rgba(239,68,68,.15);color:var(--red);border:1px solid rgba(239,68,68,.3)" onclick="event.stopPropagation();rejectJob(${j.id})">✗ Reject</button>` : ''}
        ${j.status==='accepted' ? `<button class="btn btn-sm" style="background:rgba(245,158,11,.15);color:var(--amber);border:none" onclick="event.stopPropagation();updateStatus(${j.id},'on_the_way')">🚗 On the Way</button>` : ''}
        ${j.status==='on_the_way' ? `<button class="btn btn-sm btn-green" style="width:auto" onclick="event.stopPropagation();updateStatus(${j.id},'arrived')">📍 Arrived</button>` : ''}
        ${j.status==='arrived' ? `<button class="btn btn-sm btn-accent" style="width:auto" onclick="event.stopPropagation();updateStatus(${j.id},'working')">▶ Start Work</button>` : ''}
        ${j.status==='working' ? `<button class="btn btn-sm btn-green" style="width:auto" onclick="event.stopPropagation();openJob(${j.id})">✓ Complete</button>` : ''}
        ${!isOffer ? `<button class="btn btn-sm btn-outline" onclick="event.stopPropagation();navigate(${j.latitude},${j.longitude})">🗺 Navigate</button>` : ''}
        ${isRevisit ? `<button class="btn btn-sm btn-accent" style="width:100%;margin-top:6px" onclick="event.stopPropagation();startRevisit(${j.id})">📅 Start Revisit Visit</button>` : ''}
        ${isQuotation ? `<div style="font-size:11px;color:var(--amber);padding:6px 0;font-weight:600">⏳ ${j.status.replace(/_/g,' ')} — awaiting customer</div>` : ''}
        ${isPickup ? `<div style="font-size:11px;color:var(--muted);padding:6px 0">🔧 Device pickup in progress — managed by admin</div>` : ''}
      </div>
    </div>`;
  }).join('');
}


async function rejectJob(id) {
  var reason = prompt('Reason for rejecting this job (optional):') || 'Unable to take this job';
  var res = await api('POST', '/engineer/reject-job', {job_id: id, reason});
  toast(res.message || (res.success ? 'Job rejected' : 'Error'));
  if (res.success) { updateDashboard(); if(engData) { engData.status='available'; highlightStatus('available'); } }
}

async function rejectJobDetail(id) {
  var reason = prompt('Reason for rejecting? (optional):') || 'Unable to take this job';
  var res = await api('POST', '/engineer/reject-job', {job_id: id, reason});
  toast(res.message || (res.success ? 'Job rejected' : 'Error'));
  if (res.success) { showScreen('s-dashboard'); updateDashboard(); }
}

async function startRevisit(jobId) {
  // Engineer confirms they are starting the revisit visit
  // This moves the job from revisit_scheduled → accepted so engineer can proceed normally
  var res = await api('POST', '/engineer/update-status', {job_id: jobId, status: 'on_the_way'});
  if (!res.success) {
    // If update-status fails (progression check), try direct status update
    res = await api('POST', '/engineer/revisit-start', {job_id: jobId});
  }
  toast(res.message || (res.success ? '📅 Revisit started! Navigate to customer.' : 'Error'));
  if (res.success) { updateDashboard(); }
}

async function acceptJob(id) {
  var res = await api('POST', '/engineer/accept-job', {job_id: id});
  if (res.success) {
    toast('✅ Job accepted! Customer notified.');
    if (engData) { engData.status = 'busy'; highlightStatus('busy'); }
    showScreen('s-dashboard');
    updateDashboard();
  } else {
    toast(res.message || 'Could not accept job', 'error');
  }
}

async function updateStatus(id, status) {
  var res = await api('POST', '/engineer/update-status', {job_id:id, status});
  toast(res.message);
  if (res.success) updateDashboard();
}

async function setStatus(s) {
  // Cannot manually set busy - system sets it on job assignment
  if (s === 'busy') { toast('Busy status is set automatically when a job is assigned'); return; }
  // Call API to persist status
  var res = await api('POST', '/engineer/status', {status: s});
  if (!res.success) { toast(res.message || 'Could not update status'); return; }
  if (engData) engData.status = s;
  highlightStatus(s);
  localStorage.setItem('fsm_eng_user', JSON.stringify(engData));
  if (s !== 'offline') startTracking(); else stopTracking();
  toast(s === 'available' ? '✓ You are now Available' : '○ You are now Offline');
}

function highlightStatus(s) {
  ['available','busy','offline'].forEach(x => document.getElementById('btn'+x[0].toUpperCase()+x.slice(1))?.classList.remove('on-available','on-busy','on-offline'));
  var map = {available:'btnAvail',busy:'btnBusy',offline:'btnOffline'};
  if (map[s]) document.getElementById(map[s])?.classList.add('on-'+s);
}

// ---- JOB DETAIL ----
async function openJob(id) {
  var res = await api('GET', '/engineer/jobs');
  var jobs = Array.isArray(res.data) ? res.data : (res.jobs || []); var job = jobs.find(j => j.id == id);
  if (!job) return;
  currentJob = job;
  var isOffer = (job.status === 'pending' || job.status === 'assigned'); // pending=broadcast offer, assigned=admin-assigned

  document.getElementById('jdStatus').innerHTML = `<span class="badge b-${job.status}">${isOffer ? '🔔 New Job' : job.status.replace('_',' ')}</span>`;
  document.getElementById('jobDetailContent').innerHTML = `
    <div class="card">
      <div style="font-size:18px;font-weight:800;margin-bottom:4px">${job.service_name || job.service_type || 'Service'}</div>
      <div style="font-family:monospace;font-size:12px;color:var(--hint);margin-bottom:16px">${job.job_number}</div>
      <div style="display:flex;flex-direction:column;gap:10px">
        <div><div class="form-label">Customer</div><div style="font-size:15px;font-weight:600">${job.customer_name}</div></div>
        <div><div class="form-label">Phone</div><a href="tel:${job.customer_phone}" style="color:var(--accent);font-weight:600;font-size:15px">${job.customer_phone}</a></div>
        <div><div class="form-label">Address</div><div style="font-size:14px">${job.address}</div></div>
        ${job.description ? `<div><div class="form-label">Problem</div><div style="font-size:14px;color:var(--muted)">${job.description}</div></div>` : ''}
        <div><div class="form-label">Priority</div><span class="badge b-${job.priority==='urgent'?'assigned':'pending'}">${job.priority}</span></div>
        ${job.distance_km ? `<div><div class="form-label">Distance</div><div style="font-size:14px;color:var(--accent)">📍 ${job.distance_km} km from your location</div></div>` : ''}
        ${(parseFloat(job.display_amount||0) > 0 || parseFloat(job.visit_charge||0) > 0) ? `
        <div>
          <div class="form-label">Payment Breakdown</div>
          <div style="background:rgba(34,197,94,.08);border:1px solid rgba(34,197,94,.2);border-radius:10px;padding:12px;margin-top:4px">
            <div style="display:flex;justify-content:space-between;font-size:13px;padding:4px 0">
              <span style="color:var(--muted)">Service Charge</span><span>₹${parseFloat(job.amount||0).toLocaleString('en-IN',{minimumFractionDigits:2})}</span>
            </div>
            ${parseFloat(job.visit_charge||0)>0 ? `<div style="display:flex;justify-content:space-between;font-size:13px;padding:4px 0">
              <span style="color:var(--muted)">Visit Charge</span><span>₹${parseFloat(job.visit_charge||0).toLocaleString('en-IN',{minimumFractionDigits:2})}</span>
            </div>` : ''}
            <div style="display:flex;justify-content:space-between;font-size:15px;font-weight:800;border-top:1px solid rgba(34,197,94,.2);padding-top:8px;margin-top:4px">
              <span>Customer Pays</span><span style="color:var(--green)">₹${Number(job.display_amount).toLocaleString('en-IN',{minimumFractionDigits:2})}</span>
            </div>
            <div style="display:flex;justify-content:space-between;font-size:12px;padding-top:6px;color:var(--muted)">
              <span>Platform Fee (20%)</span><span>-₹${(Number(job.display_amount)*0.2).toLocaleString('en-IN',{minimumFractionDigits:2})}</span>
            </div>
            <div style="display:flex;justify-content:space-between;font-size:14px;font-weight:700;padding-top:4px">
              <span style="color:var(--green)">Your Earnings</span><span style="color:var(--green)">₹${(Number(job.display_amount)*0.8).toLocaleString('en-IN',{minimumFractionDigits:2})}</span>
            </div>
          </div>
        </div>` : ''}
      </div>
    </div>

    <div style="display:flex;flex-direction:column;gap:8px">
      <button class="btn btn-outline" onclick="navigate(${job.latitude},${job.longitude})">🗺 Open in Maps</button>
      <button class="btn btn-outline" style="border-color:#22C55E;color:#22C55E;margin-top:8px" onclick="openEngChat(${job.id})">💬 Chat with Customer</button>
      ${['accepted','on_the_way','arrived','working','awaiting_quotation'].includes(job.status) ? `
      <button class="btn btn-sm" style="background:rgba(245,158,11,.15);color:var(--amber);border:1px solid rgba(245,158,11,.3);width:100%;padding:12px;margin-top:4px" onclick="showQuotationForm(${job.id})">
        📋 Request Parts Quotation
      </button>
      <button class="btn btn-sm" style="background:rgba(123,95,255,.15);color:#9B59B6;border:1px solid rgba(123,95,255,.3);width:100%;padding:12px;margin-top:4px" onclick="showPickupForm(${job.id})">
        🔧 Request Device Pickup to Service Center
      </button>` : ''}
      ${isOffer ? `<button class="btn btn-green" onclick="acceptJob(${job.id})">✓ Accept Job</button>` : ''}
      ${isOffer ? `<button class="btn btn-red" onclick="rejectJobDetail(${job.id})" style="margin-top:4px">✗ Reject Job</button>` : ''}
      ${job.status==='accepted' ? `<button class="btn btn-accent" onclick="updateStatus(${job.id},'on_the_way');showScreen('s-dashboard')">🚗 I'm On the Way</button>` : ''}
      ${job.status==='on_the_way' ? `<button class="btn btn-green" onclick="updateStatus(${job.id},'arrived');showScreen('s-dashboard')">📍 Mark Arrived</button>` : ''}
      ${job.status==='arrived' ? `<button class="btn btn-accent" onclick="updateStatus(${job.id},'working');showScreen('s-dashboard')">▶ Start Work</button>` : ''}
      ${job.status==='working' ? `
        <!-- Parts Used Section -->
        <div class="card" style="margin-bottom:12px">
          <div style="font-size:14px;font-weight:700;margin-bottom:12px">🔩 Parts / Additional Charges</div>
          <div id="partsUsedList" style="margin-bottom:12px">
            <div style="text-align:center;font-size:13px;color:var(--muted);padding:8px">Loading parts...</div>
          </div>
          <div id="partsTotalRow" style="display:none;border-top:1px solid var(--border);padding-top:10px;display:flex;justify-content:space-between;font-weight:700;margin-bottom:12px">
            <span style="color:var(--muted)">Parts Total</span>
            <span id="partsTotalAmt" style="color:var(--amber)">₹0.00</span>
          </div>
          <!-- Add part form -->
          <div style="background:var(--surface);border-radius:10px;padding:12px">
            <div style="font-size:12px;font-weight:700;color:var(--muted);margin-bottom:8px;text-transform:uppercase;letter-spacing:.05em">Add Part / Material</div>
            <select class="form-input" id="partSelect" style="margin-bottom:8px;font-size:13px">
              <option value="">Select from inventory...</option>
            </select>
            <div style="display:flex;gap:8px;margin-bottom:8px">
              <div style="flex:1"><label class="form-label">Qty</label><input class="form-input" type="number" id="partQty" value="1" min="1" style="padding:8px"></div>
              <div style="flex:1"><label class="form-label">Price (₹)</label><input class="form-input" type="number" id="partPrice" placeholder="Auto" min="0" step="0.01" style="padding:8px"></div>
            </div>
            <button class="btn btn-accent" onclick="addPartToJob(${job.id})" style="padding:10px">+ Add Part</button>
          </div>
        </div>
        <!-- Before/After Photos -->
        <div class="card" style="margin-bottom:12px">
          <div style="font-size:14px;font-weight:700;margin-bottom:10px">📷 Job Photos</div>
          <div id="jobPhotosList" style="margin-bottom:10px"></div>
          <div style="display:flex;gap:8px;flex-wrap:wrap">
            <label style="cursor:pointer;background:rgba(79,110,247,.1);border:1.5px dashed var(--accent);border-radius:10px;padding:8px 14px;font-size:13px;color:var(--accent);font-weight:600">
              📷 Before Photo
              <input type="file" accept="image/*" capture="environment" style="display:none" onchange="uploadJobPhoto(${job.id},'before',this)">
            </label>
            <label style="cursor:pointer;background:rgba(34,197,94,.1);border:1.5px dashed var(--green);border-radius:10px;padding:8px 14px;font-size:13px;color:var(--green);font-weight:600">
              📷 After Photo
              <input type="file" accept="image/*" capture="environment" style="display:none" onchange="uploadJobPhoto(${job.id},'after',this)">
            </label>
          </div>
        </div>
        <!-- Completion with OTP -->
        <div class="card" style="margin-bottom:0">
          <div class="form-label">Completion Notes</div>
          <textarea class="form-input" id="compNotes" rows="3" placeholder="What was done, parts replaced..."></textarea>
          <div style="margin-top:12px;padding:12px;background:#FEF3C7;border-radius:10px;margin-bottom:10px">
            <div style="font-size:13px;font-weight:700;color:#92400E;margin-bottom:8px">🔐 Customer Confirmation OTP</div>
            <div style="font-size:12px;color:#B45309;margin-bottom:10px">Request an OTP from the customer to confirm job completion. This prevents disputes.</div>
            <div id="otpRequestArea">
              <button class="btn btn-outline btn-sm" style="border-color:#D97706;color:#D97706;width:100%" onclick="requestCompletionOtp(${job.id})">📲 Send OTP to Customer</button>
            </div>
            <div id="otpVerifyArea" style="display:none;margin-top:10px">
              <div style="display:flex;gap:8px">
                <input class="form-input" id="custOtp" placeholder="Enter 4-digit OTP" maxlength="4" type="number" style="flex:1;padding:10px;font-size:18px;text-align:center;letter-spacing:6px;font-weight:700">
                <button class="btn btn-green btn-sm" onclick="verifyAndComplete(${job.id})">✓ Verify</button>
              </div>
            </div>
          </div>
          <button class="btn btn-green" style="margin-top:4px" onclick="completeJob(${job.id})">✓ Complete without OTP</button>
        </div>` : ''}
    </div>`;

  showScreen('s-jobdetail');
  // Load parts section if job is in working state
  if (job.status === 'working') {
    setTimeout(function(){ loadPartsForJob(job.id); }, 100);
    // Load job photos for before/after upload section
    setTimeout(function(){
      var photoList = document.getElementById('jobPhotosList');
      if (photoList) loadJobPhotos(job.id);
    }, 200);
  }
}

async function completeJob(id) {
  // Prevent double-click
  var btn = document.querySelector('.btn-green[onclick*="completeJob"]');
  if (btn) { btn.disabled = true; btn.textContent = 'Completing...'; }
  var notes = document.getElementById('compNotes') ? document.getElementById('compNotes').value : '';
  var res = await api('POST', '/engineer/complete-job', {job_id: parseInt(id), notes: notes});
  if (res.success) {
    showCashCollectionModal(id, res.data);
  } else if (res.message && res.message.toLowerCase().includes('already completed')) {
    // Job already done — just show cash modal with default data
    showCashCollectionModal(id, {full_amount: 0, your_earning: 0, payment_method: 'cash'});
  } else {
    if (btn) { btn.disabled = false; btn.textContent = '✓ Complete without OTP'; }
    toast(res.message || 'Cannot complete job', 'error');
  }
}

function showCashCollectionModal(jobId, data) {
  var earning  = data ? data.your_earning || 0 : 0;
  var fullAmt  = data ? data.full_amount  || 0 : 0;
  var payMethod = data ? (data.payment_method || 'cash') : 'cash';

  // Remove any existing modal
  var existing = document.getElementById('cashModal');
  if (existing) existing.remove();

  var modal = document.createElement('div');
  modal.id = 'cashModal';
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.7);z-index:9999;display:flex;align-items:flex-end';
  var isPaid = (payMethod === 'online' || payMethod === 'wallet');
  var amtFmt = Number(fullAmt).toLocaleString('en-IN', {minimumFractionDigits:2});
  var ernFmt = Number(earning).toLocaleString('en-IN', {minimumFractionDigits:2});
  var fullFmt = Number(fullAmt).toLocaleString('en-IN');
  var payLabel = payMethod === 'wallet' ? 'Customer Wallet' : 'Online Payment';
  var html = '<div style="background:var(--bg2);border-radius:24px 24px 0 0;padding:24px;width:100%;max-height:80vh;overflow-y:auto">'
    + '<div style="text-align:center;margin-bottom:20px">'
    + '<div style="font-size:48px">&#x2705;</div>'
    + '<div style="font-size:20px;font-weight:800;margin-top:8px">Job Completed!</div>'
    + '<div style="font-size:13px;color:var(--muted);margin-top:4px">Collect payment from customer</div>'
    + '</div>'
    + '<div style="background:var(--surface);border-radius:14px;padding:16px;margin-bottom:16px">'
    + '<div style="display:flex;justify-content:space-between;margin-bottom:8px;font-size:13px">'
    + '<span style="color:var(--muted)">Customer Pays</span>'
    + '<span style="font-weight:800;font-size:18px;color:var(--accent)">&#8377;' + amtFmt + '</span>'
    + '</div>'
    + '<div style="display:flex;justify-content:space-between;font-size:13px">'
    + '<span style="color:var(--muted)">Your Earnings</span>'
    + '<span style="font-weight:700;color:var(--green)">&#8377;' + ernFmt + '</span>'
    + '</div></div>';
  if (isPaid) {
    html += '<div style="background:#052810;border:1px solid #22C55E;border-radius:12px;padding:14px;margin-bottom:16px;font-size:13px;color:#86EFAC">Payment collected via ' + payLabel + '. No cash needed.</div>'
      + '<button class="btn btn-green" onclick="closeCashModal(' + jobId + ', true)">Done</button>';
  } else {
    html += '<div style="font-size:14px;font-weight:700;margin-bottom:10px">Confirm Amount Collected</div>'
      + '<div style="display:flex;gap:8px;margin-bottom:14px;align-items:center">'
      + '<span style="font-size:18px">&#8377;</span>'
      + '<input class="form-input" type="number" id="cashCollectedAmt" value="' + fullAmt.toFixed(2) + '" step="0.01" style="font-size:20px;font-weight:700;text-align:center;flex:1">'
      + '</div>'
      + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px">'
      + '<button class="btn btn-outline btn-sm" onclick="setCashAmt(' + fullAmt + ')">Full Amount</button>'
      + '<button class="btn btn-outline btn-sm" onclick="setCashAmt(0)">Free / Warranty</button>'
      + '</div>'
      + '<button class="btn btn-green" style="margin-bottom:10px" onclick="confirmCashCollected(' + jobId + ')">Cash Collected - Done</button>'
      + '<button class="btn btn-outline btn-sm" style="width:100%;opacity:.6" onclick="closeCashModal(' + jobId + ', false)">Skip</button>';
  }
  html += '</div>';
  modal.innerHTML = html;
  document.body.appendChild(modal);
}

function setCashAmt(amt) {
  var el = document.getElementById('cashCollectedAmt');
  if (el) el.value = Number(amt).toFixed(2);
}

async function confirmCashCollected(jobId) {
  var amtEl = document.getElementById('cashCollectedAmt');
  var amt = parseFloat(amtEl ? amtEl.value : 0);
  if (isNaN(amt) || amt < 0) return toast('Enter valid amount', 'error');
  // Disable button to prevent double-submit
  var btns = document.querySelectorAll('#cashModal .btn-green');
  btns.forEach(function(b){ b.disabled = true; b.textContent = 'Processing...'; });
  var res = await api('POST', '/payment/cash-confirm', {job_id: jobId, amount: amt});
  if (res.success) {
    closeCashModal(jobId, true);
    toast('Payment recorded! Invoice: ' + (res.data.invoice_number || ''), 'success');
  } else if (res.message && (res.message.toLowerCase().includes('already recorded') || res.message.toLowerCase().includes('already'))) {
    // Already recorded — just close modal gracefully
    closeCashModal(jobId, true);
    toast('Job completed!', 'success');
  } else {
    btns.forEach(function(b){ b.disabled = false; b.textContent = 'Cash Collected - Done'; });
    toast(res.message || 'Failed to record payment', 'error');
  }
}

function closeCashModal(jobId, success) {
  var modal = document.getElementById('cashModal');
  if (modal) modal.remove();
  if (success) {
    toast('Job completed successfully!');
  }
  updateDashboard();
  showScreen('s-dashboard');
}

// ── QUOTATION ──────────────────────────────────────────────
var quotationParts = [];

function showQuotationForm(jobId) {
  document.getElementById('qJobId').value = jobId;
  quotationParts = [];
  renderQuotationParts();
  document.getElementById('qNotes').value = '';
  document.getElementById('qVisitCharge').value = '';
  showScreen('s-quotation');
}

function addQuotationPart() {
  quotationParts.push({name:'',qty:1,est_price:'',unit:'piece'});
  renderQuotationParts();
}

function removeQuotationPart(idx) {
  quotationParts.splice(idx,1);
  renderQuotationParts();
}

function renderQuotationParts() {
  var el = document.getElementById('quotationPartsList');
  if (!el) return;
  if (!quotationParts.length) {
    el.innerHTML = '<div style="text-align:center;font-size:13px;color:var(--muted);padding:8px">No parts added — tap + Add Part</div>';
    return;
  }
  el.innerHTML = quotationParts.map(function(p, i) {
    return '<div style="background:var(--surface);border-radius:10px;padding:10px;margin-bottom:8px">' +
      '<div style="display:flex;gap:6px;align-items:center;margin-bottom:6px">' +
        '<input class="form-input" style="flex:2;padding:8px;font-size:13px" placeholder="Part name" value="'+p.name+'" oninput="quotationParts['+i+'].name=this.value">' +
        '<button onclick="removeQuotationPart('+i+')" style="background:rgba(239,68,68,.15);border:none;color:var(--red);padding:6px 10px;border-radius:8px;cursor:pointer">✕</button>' +
      '</div>' +
      '<div style="display:flex;gap:6px">' +
        '<div style="flex:1"><label class="form-label" style="font-size:10px">Qty</label><input class="form-input" type="number" style="padding:8px;font-size:13px" value="'+p.qty+'" min="1" oninput="quotationParts['+i+'].qty=parseInt(this.value)||1"></div>' +
        '<div style="flex:1"><label class="form-label" style="font-size:10px">Est. Price (₹)</label><input class="form-input" type="number" style="padding:8px;font-size:13px" placeholder="Optional" value="'+p.est_price+'" oninput="quotationParts['+i+'].est_price=this.value"></div>' +
        '<div style="flex:1"><label class="form-label" style="font-size:10px">Unit</label><input class="form-input" style="padding:8px;font-size:13px" value="'+p.unit+'" placeholder="piece/meter" oninput="quotationParts['+i+'].unit=this.value"></div>' +
      '</div>' +
    '</div>';
  }).join('');
}

async function submitQuotation() {
  var jobId   = parseInt(document.getElementById('qJobId').value);
  var notes   = document.getElementById('qNotes').value.trim();
  var vCharge = parseFloat(document.getElementById('qVisitCharge').value) || 0;
  if (!notes) return toast('Please describe the issue for the backend team', 'error');
  var validParts = quotationParts.filter(function(p){ return p.name.trim(); });
  var res = await api('POST', '/engineer/quotation', {job_id: jobId, notes: notes, parts: validParts, visit_charge: vCharge});
  toast(res.message || (res.success ? 'Quotation submitted!' : 'Error'));
  if (res.success) { showScreen('s-dashboard'); updateDashboard(); }
}

// ── PICKUP ──────────────────────────────────────────────────
function showPickupForm(jobId) {
  document.getElementById('pickupJobId').value = jobId;
  document.getElementById('pickupDevice').value  = '';
  document.getElementById('pickupNotes').value   = '';
  document.getElementById('pickupAddress').value = '';
  showScreen('s-pickup');
}

async function submitPickup() {
  var jobId   = parseInt(document.getElementById('pickupJobId').value);
  var device  = document.getElementById('pickupDevice').value.trim();
  var notes   = document.getElementById('pickupNotes').value.trim();
  var address = document.getElementById('pickupAddress').value.trim();
  if (!device) return toast('Enter the device name/model', 'error');
  if (!notes)  return toast('Describe the issue', 'error');
  var res = await api('POST', '/engineer/pickup', {job_id: jobId, device_desc: device, pickup_notes: notes, pickup_address: address});
  toast(res.message || (res.success ? 'Pickup request submitted!' : 'Error'));
  if (res.success) { showScreen('s-dashboard'); updateDashboard(); }
}

async function loadPartsForJob(jobId) {
  // Load engineer inventory for part select
  var invRes = await api('GET', '/engineer/inventory');
  var sel = document.getElementById('partSelect');
  if (sel && invRes.success && invRes.data && invRes.data.length) {
    sel.innerHTML = '<option value="">Select from inventory...</option>' +
      invRes.data.filter(function(p){ return p.qty > 0; })
               .map(function(p){
                 return '<option value="' + p.part_id + '" data-price="' + (p.sell_price || p.cost_price || 0) + '">' +
                   p.name + ' (Stock: ' + p.qty + ', ₹' + parseFloat(p.sell_price || p.cost_price || 0).toLocaleString('en-IN') + ')</option>';
               }).join('');
    // Auto-fill price when part selected
    sel.addEventListener('change', function() {
      var opt = sel.options[sel.selectedIndex];
      var priceEl = document.getElementById('partPrice');
      if (priceEl && opt.dataset.price) priceEl.placeholder = '₹' + opt.dataset.price;
    });
  } else if (sel) {
    sel.innerHTML = '<option value="">No parts in inventory</option>';
  }

  // Load parts already added to this job
  refreshJobParts(jobId);
}

async function refreshJobParts(jobId) {
  var res = await api('GET', '/engineer/job-parts?job_id=' + jobId);
  var listEl  = document.getElementById('partsUsedList');
  var totalEl = document.getElementById('partsTotalAmt');
  var totalRow = document.getElementById('partsTotalRow');
  if (!listEl) return;
  if (!res.success || !res.data.parts.length) {
    listEl.innerHTML = '<div style="text-align:center;font-size:13px;color:var(--muted);padding:8px">No parts added yet</div>';
    if (totalRow) totalRow.style.display = 'none';
    return;
  }
  listEl.innerHTML = res.data.parts.map(function(p) {
    return '<div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--border)">' +
      '<div style="flex:1">' +
        '<div style="font-size:13px;font-weight:600">' + p.name + '</div>' +
        '<div style="font-size:11px;color:var(--muted)">× ' + p.qty + ' @ ₹' + parseFloat(p.unit_price).toLocaleString('en-IN', {minimumFractionDigits:2}) + '</div>' +
      '</div>' +
      '<div style="font-weight:700;color:var(--amber)">₹' + parseFloat(p.subtotal).toLocaleString('en-IN', {minimumFractionDigits:2}) + '</div>' +
      '<button onclick="removePartFromJob(' + p.id + ',' + (currentJob && currentJob.id ? currentJob.id : 0) + ')" ' +
        'style="background:rgba(239,68,68,.1);border:none;color:var(--red);padding:4px 8px;border-radius:6px;cursor:pointer;font-size:12px">✕</button>' +
    '</div>';
  }).join('');
  if (totalEl) totalEl.textContent = '₹' + parseFloat(res.data.parts_total).toLocaleString('en-IN', {minimumFractionDigits:2});
  if (totalRow) totalRow.style.display = 'flex';
}

async function addPartToJob(jobId) {
  var partId = document.getElementById('partSelect') ? parseInt(document.getElementById('partSelect').value) : 0;
  var qty    = document.getElementById('partQty')    ? parseInt(document.getElementById('partQty').value)    : 1;
  var price  = document.getElementById('partPrice')  ? document.getElementById('partPrice').value             : '';
  if (!partId) return toast('Select a part first', 'error');
  if (!qty || qty < 1) return toast('Enter valid quantity', 'error');
  var body = {job_id: jobId, part_id: partId, qty: qty};
  if (price) body.unit_price = parseFloat(price);
  var res = await api('POST', '/engineer/job-parts', body);
  toast(res.message || (res.success ? 'Part added!' : 'Error'));
  if (res.success) {
    document.getElementById('partSelect').value = '';
    document.getElementById('partQty').value    = '1';
    document.getElementById('partPrice').value  = '';
    refreshJobParts(jobId);
  }
}

async function removePartFromJob(entryId, jobId) {
  var res = await api('POST', '/engineer/job-parts', {action: 'remove', entry_id: entryId});
  toast(res.message || (res.success ? 'Part removed' : 'Error'));
  if (res.success) refreshJobParts(jobId);
}

// ---- HISTORY ----
async function loadHistory() {
  var res = await api('GET', '/engineer/jobs?filter=history');
  var cont = document.getElementById('historyContent');
  if (!res.success) { cont.innerHTML = '<div style="text-align:center;padding:40px;color:var(--hint)">Failed to load history</div>'; return; }
  var histJobs = Array.isArray(res.data) ? res.data : [];
  if (!histJobs.length) { cont.innerHTML = '<div style="text-align:center;padding:40px;color:var(--hint)">No completed jobs yet</div>'; return; }

  cont.innerHTML = histJobs.map(j => `
    <div class="card">
      <div style="display:flex;justify-content:space-between;margin-bottom:6px">
        <div style="font-weight:700">${j.service_name || j.service_type || 'Service'}</div>
        <span class="badge b-${j.status === 'completed' ? 'completed' : 'assigned'}">${j.status}</span>
      </div>
      <div style="font-size:13px;color:var(--muted)">${j.customer_name}</div>
      <div style="font-size:12px;color:var(--hint);margin-top:3px">📍 ${j.address || ''}</div>
      ${j.display_amount > 0 ? `<div style="font-size:13px;font-weight:700;color:var(--green);margin-top:4px">₹${Number(j.display_amount).toLocaleString('en-IN')}</div>` : ''}
      ${j.rating ? `<div style="font-size:12px;margin-top:6px;color:var(--amber)">★ ${j.rating} ${j.feedback ? '· '+j.feedback : ''}</div>` : ''}
      <div style="font-size:11px;color:var(--hint);margin-top:4px">${new Date(j.updated_at).toLocaleDateString('en-IN')}</div>
    </div>`).join('');
}

// ---- PROFILE ----



async function loadProfile() {
  var res = await api('GET', '/engineer/profile');
  var e = (res.success && res.data) ? res.data : engData;
  if (!e) return;
  engData = e;
  localStorage.setItem('fsm_eng_user', JSON.stringify(e));

  // Show profile photo if available, else initial
  var profInit = document.getElementById('profInit');
  if (e.profile_photo) {
    profInit.innerHTML = '<img src="'+e.profile_photo+'" style="width:72px;height:72px;border-radius:50%;object-fit:cover">';
  } else {
    profInit.textContent = e.name ? e.name[0].toUpperCase() : '?';
  }
  document.getElementById('profName').textContent  = e.name  || '—';
  document.getElementById('profPhone').textContent = e.phone || '—';

  // Populate update form
  var upName = document.getElementById('upName');
  var upArea = document.getElementById('upArea');
  if (upName) upName.value = e.name         || '';
  if (upArea) upArea.value = e.service_area || '';
  var upCity = document.getElementById('upCity');
  if (upCity) upCity.value = e.city || '';

  // Stats: use profile data if available, else fetch history
  if (e.completed_jobs !== undefined) {
    document.getElementById('pTotalJobs').textContent = e.completed_jobs || 0;
    document.getElementById('pDone').textContent      = e.completed_jobs || 0;
    document.getElementById('pRating').textContent    = e.avg_rating ? '★ ' + parseFloat(e.avg_rating).toFixed(1) : 'N/A';
  } else {
    var hist = await api('GET', '/engineer/jobs?filter=history');
    var histJobs = Array.isArray(hist.data) ? hist.data : [];
    document.getElementById('pTotalJobs').textContent = histJobs.length;
    document.getElementById('pDone').textContent      = histJobs.filter(function(j){return j.status==='completed';}).length;
    var ratings = histJobs.filter(function(j){return j.rating;}).map(function(j){return parseFloat(j.rating);});
    document.getElementById('pRating').textContent = ratings.length ? '★ '+(ratings.reduce(function(a,b){return a+b;},0)/ratings.length).toFixed(1) : 'N/A';
  }

  // Load skills
  if (e.skills && Array.isArray(e.skills)) {
    mySkills = e.skills.map(s => ({id: s.id, name: s.name}));
  }
  renderSkills();
  loadSkillsFromAPI();
  loadAvailability();
  loadMyZones();
}

