// MY ZONES — Engineer self-service zone management
// ════════════════════════════════════════════════════

async function loadMyZones() {
  await Promise.all([renderAssignedZones(), loadAvailableZones()]);
}

async function renderAssignedZones() {
  var el = document.getElementById('assignedZonesList');
  if (!el) return;

  var r = await api('GET', '/engineer/my-zones');
  var zones = (r.success && Array.isArray(r.data)) ? r.data : [];

  if (zones.length === 0) {
    el.innerHTML = '<div style="text-align:center;color:var(--muted);font-size:13px;padding:8px">You have not joined any zones yet.<br>Use the dropdown below to join a zone.</div>';
    return;
  }

  var html = '';
  for (var i = 0; i < zones.length; i++) {
    var z = zones[i];
    var avail    = z.is_available ? 1 : 0;
    var btnStyle = avail
      ? 'background:rgba(34,197,94,.2);color:#22C55E'
      : 'background:rgba(85,90,122,.2);color:#8B90B0';
    var btnLabel = avail ? '✅ Active' : '⏸ Paused';
    var btnTitle = avail ? 'Receiving jobs. Tap to pause.' : 'Paused. Tap to activate.';
    var meta     = z.city + (z.state ? ', ' + z.state : '') + (z.radius_km ? ' · ' + z.radius_km + ' km' : '');

    html += '<div style="display:flex;align-items:center;gap:10px;padding:10px 0;border-bottom:1px solid var(--border)" id="zrow-' + z.id + '">';
    html +=   '<div style="flex:1;min-width:0">';
    html +=     '<div style="font-weight:700;font-size:13px">' + z.name + '</div>';
    html +=     '<div style="font-size:11px;color:var(--muted);margin-top:2px">' + meta + '</div>';
    html +=   '</div>';
    html +=   '<button id="ztoggle-' + z.id + '" onclick="event.stopPropagation();toggleZoneAvail(' + z.id + ')" title="' + btnTitle + '" style="padding:6px 12px;border-radius:20px;font-size:11px;font-weight:700;border:none;cursor:pointer;' + btnStyle + '">' + btnLabel + '</button>';
    html +=   '<button onclick="event.stopPropagation();leaveZone(' + z.id + ')" title="Leave zone" data-zone-name="' + z.name.replace(/"/g,'') + '" style="padding:6px 10px;border-radius:20px;font-size:11px;font-weight:700;border:none;cursor:pointer;background:rgba(239,68,68,.15);color:#EF4444">\u2715</button>';
    html += '</div>';
  }
  el.innerHTML = html;
}
async function loadAvailableZones() {
  var sel = document.getElementById('zoneJoinSelect');
  if (!sel) return;

  // Get all active zones
  var allR = await api('GET', '/engineer/available-zones');
  var available = (allR.success && Array.isArray(allR.data)) ? allR.data : [];

  if (available.length === 0) {
    sel.innerHTML = '<option value="">No more zones to join</option>';
    return;
  }
  sel.innerHTML = '<option value="">— Select a zone to join —</option>'
    + available.map(function(z) {
        return '<option value="' + z.id + '">' + z.name + ' — ' + z.city + (z.radius_km ? ' (' + z.radius_km + ' km)' : '') + '</option>';
      }).join('');
}

async function joinZone() {
  var sel = document.getElementById('zoneJoinSelect');
  var zoneId = parseInt(sel ? sel.value : 0);
  if (!zoneId) { showToastEng('Please select a zone to join.', 'error'); return; }

  var r = await api('POST', '/engineer/join-zone', { zone_id: zoneId });
  if (r.success) {
    showToastEng('✅ ' + (r.message || 'Joined zone successfully!'), 'success');
    sel.value = '';
    await loadMyZones();
  } else {
    showToastEng(r.message || 'Failed to join zone', 'error');
  }
}

async function leaveZone(zoneId) {
  var btn = document.querySelector('[data-zone-name]');
  var zoneName = 'this zone';
  // find the matching button by onclick
  document.querySelectorAll('[data-zone-name]').forEach(function(b){ if(b.getAttribute('onclick') && b.getAttribute('onclick').indexOf('leaveZone('+zoneId+')') >= 0) zoneName = b.getAttribute('data-zone-name') || zoneName; });
  if (!confirm('Leave zone ' + zoneName + '? You will stop receiving job notifications from this zone.')) return;

  var r = await api('POST', '/engineer/leave-zone', { zone_id: zoneId });
  if (r.success) {
    showToastEng('Left zone: ' + zoneName, 'success');
    await loadMyZones();
  } else {
    showToastEng(r.message || 'Failed to leave zone', 'error');
  }
}

async function toggleZoneAvail(zoneId) {
  // Find button by its stable id attribute
  var btn = document.getElementById('ztoggle-' + zoneId);
  if (!btn) return;

  // Instant visual feedback
  var origText  = btn.textContent;
  var origStyle = btn.style.cssText;
  btn.textContent   = '...';
  btn.disabled      = true;
  btn.style.opacity = '0.6';

  var r = await api('POST', '/engineer/zone-availability', { zone_id: zoneId });

  btn.disabled      = false;
  btn.style.opacity = '1';

  if (r.success) {
    var isNowActive = r.data && r.data.is_available;
    btn.textContent   = isNowActive ? '\u2705 Active' : '\u23f8 Paused';
    btn.style.cssText = 'padding:6px 12px;border-radius:20px;font-size:11px;font-weight:700;border:none;cursor:pointer;'
      + (isNowActive
          ? 'background:rgba(34,197,94,.2);color:#22C55E'
          : 'background:rgba(85,90,122,.2);color:#8B90B0');
    btn.title = isNowActive ? 'Receiving jobs. Tap to pause.' : 'Paused. Tap to activate.';
    showToastEng(isNowActive ? '\u2705 Zone activated' : '\u23f8 Zone paused', 'success');
  } else {
    btn.textContent   = origText;
    btn.style.cssText = origStyle;
    showToastEng(r.message || 'Toggle failed. Please try again.', 'error');
  }
}

// Small toast for engineer app (reuse existing if present)
function showToastEng(msg, type) {
  if (typeof showToast === 'function') { showToast(msg, type); return; }
  var t = document.createElement('div');
  var bg = type === 'success' ? 'var(--green)' : 'var(--red)';
  t.style.cssText = 'position:fixed;bottom:90px;left:50%;transform:translateX(-50%);'
    + 'background:' + bg + ';color:#fff;padding:10px 20px;border-radius:20px;'
    + 'font-size:13px;font-weight:700;z-index:9999;white-space:nowrap;'
    + 'box-shadow:0 4px 20px rgba(0,0,0,.3);transition:opacity .3s';
  t.textContent = msg;
  document.body.appendChild(t);
  setTimeout(function() { t.style.opacity = '0'; setTimeout(function() { t.remove(); }, 300); }, 2500);
}

// ---- AVAILABILITY ────────────────────────────────────────────
var _availData = null; // {slots, dates, schedule}

async function loadAvailability() {
  var res = await api('GET', '/engineer/availability');
  if (!res.success) return;
  _availData = res.data;
  renderAvailabilityGrid();
}

function renderAvailabilityGrid() {
  var el = document.getElementById('availabilityGrid');
  if (!el || !_availData) return;
  var slots = _availData.slots || [];
  var dates = _availData.dates || [];
  var sched = _availData.schedule || {};
  var days = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];

  var html = '<table style="border-collapse:collapse;min-width:100%;font-size:12px">';
  // Header row — dates
  html += '<thead><tr><th style="padding:6px 8px;text-align:left;color:var(--muted);font-weight:600;white-space:nowrap">Slot</th>';
  dates.forEach(function(d) {
    var dt = new Date(d + 'T00:00:00');
    var isToday = d === new Date().toISOString().slice(0,10);
    html += '<th style="padding:6px 4px;text-align:center;color:' + (isToday ? 'var(--accent)' : 'var(--muted)') + ';font-weight:' + (isToday ? '700' : '600') + ';min-width:44px">' +
      days[dt.getDay()] + '<br><span style="font-size:10px">' + dt.getDate() + '/' + (dt.getMonth()+1) + '</span></th>';
  });
  html += '</tr></thead><tbody>';

  // One row per slot
  slots.forEach(function(slot) {
    html += '<tr><td style="padding:6px 8px;color:var(--text);font-size:11px;white-space:nowrap;border-top:1px solid var(--border)">' + slot.label + '</td>';
    dates.forEach(function(d) {
      var isAvail = sched[d] && sched[d][slot.id] !== undefined ? sched[d][slot.id] : true; // default available
      var isPast  = d < new Date().toISOString().slice(0,10);
      html += '<td style="padding:4px;text-align:center;border-top:1px solid var(--border)">' +
        '<input type="checkbox" data-slot="' + slot.id + '" data-date="' + d + '" ' +
        (isAvail ? 'checked' : '') + (isPast ? ' disabled' : '') +
        ' style="width:18px;height:18px;accent-color:var(--accent);cursor:' + (isPast ? 'not-allowed' : 'pointer') + '">' +
        '</td>';
    });
    html += '</tr>';
  });
  html += '</tbody></table>';
  html += '<div style="font-size:11px;color:var(--hint);margin-top:8px">✓ = Available &nbsp; ☐ = Not available &nbsp; Greyed = Past date</div>';
  el.innerHTML = html;
}

async function saveAvailability() {
  var checkboxes = document.querySelectorAll('#availabilityGrid input[type="checkbox"]');
  var rows = [];
  checkboxes.forEach(function(cb) {
    if (!cb.disabled) {
      rows.push({ slot_id: parseInt(cb.dataset.slot), date: cb.dataset.date, is_available: cb.checked ? 1 : 0 });
    }
  });
  if (!rows.length) { toast('Nothing to save'); return; }
  var res = await api('POST', '/engineer/availability', {availability: rows});
  toast(res.message || (res.success ? 'Schedule saved!' : 'Error'), res.success ? '' : 'error');
}

