// ---- GPS TRACKING ----
var jobPollTimer = null;

function startTracking() {
  if (locationTimer) return;
  document.getElementById('locStatus').style.display = 'flex';
  sendLocation();
  locationTimer = setInterval(sendLocation, 8000);
  // Poll for new job offers every 15 seconds
  if (!jobPollTimer) jobPollTimer = setInterval(function() {
    updateDashboard();
    loadNotifications();
  }, 15000);
}

function stopTracking() {
  clearInterval(locationTimer);
  locationTimer = null;
  clearInterval(jobPollTimer);
  jobPollTimer = null;
  document.getElementById('locStatus').style.display = 'none';
}

// stopTracking merged above


function sendLocation() {
  if (!navigator.geolocation || !token) return;
  navigator.geolocation.getCurrentPosition(pos => {
    api('POST', '/engineer/location', {
      latitude:  pos.coords.latitude,
      longitude: pos.coords.longitude,
      speed:     pos.coords.speed || 0,
      heading:   pos.coords.heading || 0,
      accuracy:  pos.coords.accuracy || 0,
      timestamp: Math.floor(Date.now()/1000),
      job_id:    currentJob?.id || null
    });
  });
}

// ---- UTILS ----
function showScreen(id, navEl) {
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  var el = document.getElementById(id);
  if (el) el.classList.add('active');
  // Sync all nav instances
  var navMap = {'s-dashboard':'nav-dashboard','s-history':'nav-history','s-wallet':'nav-wallet','s-profile':'nav-profile','s-notifications':'nav-notif'};
  document.querySelectorAll('.nav-btn').forEach(b => b.classList.remove('active'));
  var navId = navMap[id];
  if (navId) {
    document.querySelectorAll('[id="'+navId+'"]').forEach(b => b.classList.add('active'));
  } else if (navEl) {
    navEl.classList.add('active');
  }
  // Load data
  if (id === 's-history')   setTimeout(loadHistory, 50);
  if (id === 's-profile')   setTimeout(loadProfile, 50);
  if (id === 's-dashboard') setTimeout(updateDashboard, 50);
  if (id === 's-wallet')        setTimeout(loadWallet, 50);
  if (id === 's-notifications') setTimeout(loadNotifications, 50);
}

async function loadNotifications() {
  var res = await api('GET', '/engineer/notifications');
  var el = document.getElementById('notifListEng');
  if (!el) return;
  if (!res.success) { el.innerHTML = '<div style="text-align:center;padding:40px;color:var(--hint)">Failed to load</div>'; return; }
  var notifs = res.data.notifications || [];
  // Update badge
  var badge = document.getElementById('notifBadge');
