  if (!notifs.length) { el.innerHTML = '<div style="text-align:center;padding:40px;color:var(--hint)">No notifications</div>'; return; }
  el.innerHTML = notifs.map(n => `
    <div class="card" style="padding:12px;margin-bottom:8px;opacity:${n.is_read?0.6:1}">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px">
