          <div style="font-size:13px;font-weight:${n.is_read?'500':'700'}">${n.title}</div>
          <div style="font-size:12px;color:var(--muted);margin-top:3px">${n.body}</div>
        </div>
        <div style="font-size:11px;color:var(--hint);flex-shrink:0">${new Date(n.created_at).toLocaleDateString('en-IN')}</div>
      </div>
    </div>`).join('');
}

