}




// ---- API ----
async function api(method, path, data) {
  var opts = {method, headers:{'Authorization':'Bearer '+token}};
  if (data && method !== 'GET') {
    if (data instanceof FormData) {
      opts.body = data; // browser sets multipart Content-Type automatically
    } else {
      opts.headers['Content-Type'] = 'application/json';
      opts.body = JSON.stringify(data);
    }
  }
  try {
    var r = await fetch(API + path, opts);
    var text = await r.text();
    if (!text || text.trim()==='') return {success:false, message:'Empty response'};
    try { return JSON.parse(text); } catch(e) { return {success:false, message:'Invalid response'}; }
  } catch(e) { return {success:false, message:'Network error'}; }
}

// ---- LOGIN ----
async function login() {
  var email = document.getElementById('lPhone').value.trim();
  var pass  = document.getElementById('lPass').value;
  if (!email || !pass) return toast('Email and password required');

  var res = await apiNoAuth('POST', '/auth/engineer/login', {email, password: pass});

  // KYC not complete — offer to resume
  if (!res.success && res.data && res.data.resume_kyc) {
    kycEngineerId = res.data.engineer_id;
    var stepMap = {selfie:'s-kyc-selfie'};
    var nextScreen = stepMap[res.data.next_step] || 's-kyc-selfie';
    if (confirm(res.message + '\n\nTap OK to continue your KYC verification.')) {
      showScreen(nextScreen);
    }
    return;
  }

  if (!res.success) { toast(res.message || 'Login failed'); return; }

  token   = res.data ? res.data.token    : res.token;
  engData = res.data ? res.data.engineer : res.user;
  localStorage.setItem('fsm_eng_token', token);
  localStorage.setItem('fsm_eng_user', JSON.stringify(engData));
  showScreen('s-dashboard');
  updateDashboard();
  startTracking();
  // Save FCM device token for push notifications
  registerFcmToken();
}

async function registerFcmToken() {
  try {
    if (!('serviceWorker' in navigator) || !('PushManager' in window)) return;
    var settRes = await apiNoAuth('GET', '/admin/settings');
    if (!settRes.success || !settRes.data) return;
    var s = settRes.data;
    if (!s.fcm_server_key && !s.fcm_api_key) return;
    var firebaseConfig = {
      apiKey:            s.fcm_api_key            || '',
      authDomain:        (s.fcm_project_id||'')   + '.firebaseapp.com',
      projectId:         s.fcm_project_id         || '',
      messagingSenderId: s.fcm_sender_id          || '',
      appId:             s.fcm_app_id             || '',
      vapidKey:          s.fcm_vapid_key          || '',
    };
    if (!firebaseConfig.projectId) return;
    var reg = await navigator.serviceWorker.register('/firebase-messaging-sw.js');
    var { initializeApp }  = await import('https://www.gstatic.com/firebasejs/10.7.1/firebase-app.js');
    var { getMessaging, getToken } = await import('https://www.gstatic.com/firebasejs/10.7.1/firebase-messaging.js');
    var app       = initializeApp(firebaseConfig, 'hridya-engineer');
    var messaging = getMessaging(app);
    var fcmToken  = await getToken(messaging, { serviceWorkerRegistration: reg, vapidKey: firebaseConfig.vapidKey });
    if (fcmToken && engData && engData.id) {
      await fetch(API + '/auth/device-token', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
        body: JSON.stringify({ device_token: fcmToken, user_type: 'engineer', user_id: engData.id })
      });
    }
  } catch(e) { /* FCM optional — don't block login */ }
}

function logout() {
  api('POST', '/auth/logout', {});
  clearInterval(locationTimer);
  localStorage.clear();
  token = null; engData = null;
  showScreen('s-login');
}

