async function saveProfile() {
  var name  = document.getElementById('upName').value.trim();
  var city  = document.getElementById('upCity') ? document.getElementById('upCity').value.trim() : '';
  var area  = document.getElementById('upArea').value.trim();
  var pass  = document.getElementById('upPass').value;
  var photo = document.getElementById('upPhoto').files[0];
  if (!name) return toast('Name is required');
  // Use FormData to support photo upload
  var fd = new FormData();
  fd.append('name', name);
  fd.append('city', city);
  fd.append('service_area', area);
  if (pass) fd.append('password', pass);
  if (photo) fd.append('photo', photo);
  var res = await api('POST', '/engineer/update-profile', fd);
  toast(res.message || (res.success ? 'Profile updated!' : 'Error'));
  if (res.success && engData) {
    engData.name = name;
    engData.service_area = area;
    localStorage.setItem('fsm_eng_user', JSON.stringify(engData));
    document.getElementById('profName').textContent  = name;
    document.getElementById('profInit').textContent  = name[0].toUpperCase();
    document.getElementById('dashName').textContent  = name;
    // Update avatar with new photo
    if (photo) {
      var prev = document.getElementById('engPhotoPreview');
      if (prev && prev.src) {
        document.getElementById('profInit').innerHTML = '<img src="'+prev.src+'" style="width:72px;height:72px;border-radius:50%;object-fit:cover">';
      }
    }
