}

// ---- SKILLS ----
var mySkills = [];
// mySkills = array of {id, name}
var mySkillIds = [];

function renderSkills() {
  var el = document.getElementById('skillsList');
  if (!el) return;
  if (!mySkills.length) {
    el.innerHTML = '<span style="font-size:13px;color:var(--muted)">No skills added yet</span>';
    return;
  }
  el.innerHTML = mySkills.map(s =>
    '<span style="background:rgba(79,110,247,.15);color:var(--accent);border:1px solid rgba(79,110,247,.3);border-radius:20px;padding:4px 12px;font-size:12px;font-weight:600;display:inline-flex;align-items:center;gap:6px">' +
    (s.name || s) +
    '<span onclick="removeSkill(' + (s.id || JSON.stringify(s)) + ')" style="cursor:pointer;opacity:.7;margin-left:4px">×</span></span> '
  ).join('');
}

async function loadSkillsFromAPI() {
  // FIX: Use /engineer/skills endpoint (not admin) — or customer/services as fallback
  var sel = document.getElementById('skillSelect');
  if (!sel) return;
  try {
    // Try engineer skills endpoint first, fallback to admin (works if same token accepted)
    var res = await api('GET', '/engineer/skills');
    if (!res.success) res = await api('GET', '/admin/skills');
    if (res.success && res.data) {
      sel.innerHTML = '<option value="">Select a skill...</option>' +
        res.data.filter(function(s){ return s.is_active; })
               .map(function(s){ return '<option value="' + s.id + '">' + s.name + '</option>'; }).join('');
    } else {
      sel.innerHTML = '<option value="">No skills available</option>';
    }
  } catch(e) {
    sel.innerHTML = '<option value="">Could not load skills</option>';
  }
}

async function addSkill() {
  var sel = document.getElementById('skillSelect');
  var skillId = parseInt(sel.value);
  var skillName = sel.options[sel.selectedIndex]?.text;
  if (!skillId) return toast('Select a skill first');
  if (mySkills.find(s => s.id == skillId)) return toast('Skill already added');
  mySkills.push({id: skillId, name: skillName});
  sel.value = '';
  renderSkills();
  await saveSkills();
  toast(skillName + ' added!');
}

async function removeSkill(skillId) {
  mySkills = mySkills.filter(s => (s.id || s) != skillId);
  renderSkills();
  await saveSkills();
  toast('Skill removed');
}

async function saveSkills() {
  var ids = mySkills.map(s => s.id || s);
  await api('POST', '/engineer/update-profile', {skills: ids});
}


// ── FORGOT / RESET PASSWORD ────────────────────────────
function showForgotPassword() {
  var emailEl = document.getElementById('lPhone');
  if (emailEl && document.getElementById('forgotEmail')) document.getElementById('forgotEmail').value = emailEl.value || '';
  document.getElementById('forgotMsg').style.display = 'none';
  showScreen('s-forgot');
}

async function requestPasswordReset() {
  var email = document.getElementById('forgotEmail').value.trim();
  var msgEl = document.getElementById('forgotMsg');
  if (!email) { showResetMsg(msgEl, 'Enter your email address', 'error'); return; }
  var btn = event.target; btn.disabled=true; btn.textContent='Sending...';
  var res = await apiNoAuth('POST', '/auth/forgot-password', {email:email, user_type:'engineer'});
  btn.disabled=false; btn.textContent='📧 Send Reset Link';
  showResetMsg(msgEl, res.message || (res.success ? 'Check your email!' : 'Error'), res.success ? 'success' : 'error');
}

async function submitPasswordReset() {
  var pass1 = document.getElementById('resetPass1').value;
  var pass2 = document.getElementById('resetPass2').value;
  var msgEl = document.getElementById('resetMsg');
  if (!pass1 || pass1.length < 6) { showResetMsg(msgEl, 'Password must be at least 6 characters', 'error'); return; }
  if (pass1 !== pass2) { showResetMsg(msgEl, 'Passwords do not match', 'error'); return; }
  var btn = event.target; btn.disabled=true; btn.textContent='Saving...';
  var res = await apiNoAuth('POST', '/auth/reset-password', {token: window._resetToken||'', password: pass1});
  btn.disabled=false; btn.textContent='🔒 Set New Password';
  if (res.success) {
    showResetMsg(msgEl, '✅ ' + res.message, 'success');
    setTimeout(function(){ showScreen('s-login'); }, 2500);
  } else { showResetMsg(msgEl, res.message || 'Error', 'error'); }
}

function showResetMsg(el, msg, type) {
  if (!el) return;
  el.textContent = msg; el.style.display = 'block';
  el.style.background = type==='error' ? 'rgba(239,68,68,.15)' : 'rgba(34,197,94,.15)';
  el.style.color = type==='error' ? 'var(--red)' : 'var(--green)';
  el.style.border = '1px solid ' + (type==='error' ? 'rgba(239,68,68,.3)' : 'rgba(34,197,94,.3)');
}

// Handle reset token from URL
var _urlParams = new URLSearchParams(window.location.search);
var _resetTok  = _urlParams.get('reset_token');
if (_resetTok) {
  window._resetToken = _resetTok;
  document.addEventListener('DOMContentLoaded', function(){
    document.querySelectorAll('.screen').forEach(function(s){ s.classList.remove('active'); });
    document.getElementById('s-reset').classList.add('active');
  });
}

