async function uploadJobPhoto(jobId, photoType, input) {
  if (!input.files || !input.files[0]) return;
  toast('Uploading ' + photoType + ' photo...');
  var fd = new FormData();
  fd.append('job_id', jobId);
  fd.append('photo_type', photoType);
  fd.append('photo', input.files[0]);
  var res = await api('POST', '/engineer/job-photos', fd);
  if (res.success) {
    toast('📷 ' + photoType.charAt(0).toUpperCase() + photoType.slice(1) + ' photo uploaded ✓', 'success');
    loadJobPhotos(jobId);
  } else {
    toast(res.message || 'Upload failed', 'error');
  }
}
async function loadJobPhotos(jobId) {
  var el = document.getElementById('jobPhotosList');
  if (!el) return;
  var res = await api('GET', '/engineer/job-photos?job_id=' + jobId);
  if (!res.success || !Array.isArray(res.data) || !res.data.length) {
    el.innerHTML = '<div style="font-size:12px;color:var(--muted);padding:4px 0">No photos uploaded yet</div>';
    return;
  }
  el.innerHTML = '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:4px">' +
    res.data.map(function(p) {
      return '<div style="text-align:center">' +
        '<img src="' + p.photo_url + '" style="width:72px;height:72px;object-fit:cover;border-radius:8px;border:2px solid var(--border)">' +
        '<div style="font-size:10px;font-weight:700;color:var(--muted);margin-top:2px">' + p.photo_type.toUpperCase() + '</div>' +
      '</div>';
    }).join('') + '</div>';
}

