async function requestCompletionOtp(jobId) {
  var btn = document.querySelector('#otpRequestArea button');
  if (btn) { btn.disabled = true; btn.textContent = 'Sending OTP...'; }
  var res = await api('POST', '/engineer/request-completion-otp', {job_id: jobId});
  if (btn) { btn.disabled = false; btn.textContent = '📲 Resend OTP'; }
  if (res.success) {
    toast('OTP sent to customer ✓', 'success');
    document.getElementById('otpVerifyArea').style.display = 'block';
    document.getElementById('custOtp').focus();
  } else {
    toast(res.message || 'Failed to send OTP', 'error');
  }
}
async function verifyAndComplete(jobId) {
  var otp   = document.getElementById('custOtp').value.trim();
  var notes = document.getElementById('compNotes') ? document.getElementById('compNotes').value : '';
  if (!otp || otp.length < 4) return toast('Enter 4-digit OTP', 'error');
  var res = await api('POST', '/engineer/verify-completion-otp', {job_id: parseInt(jobId), otp: otp, notes: notes});
  if (res.success) {
    showCashCollectionModal(jobId, res.data);
  } else {
    toast(res.message || 'Invalid OTP', 'error');
  }
}

// ════════════════════════════════════════════════════
// FEATURE: Real-time Chat
// ════════════════════════════════════════════════════
var engChatJobId = null;
var engChatInterval = null;

function openEngChat(jobId) {
  engChatJobId = jobId;
  document.getElementById('engChatTitle').textContent = 'Chat with Customer';
  document.getElementById('engChatMessages').innerHTML = '<div style="text-align:center;padding:20px;color:var(--muted);font-size:13px">Loading...</div>';
  showScreen('s-chat');
  loadEngChatMessages();
  engChatInterval = setInterval(loadEngChatMessages, 5000);
}
async function loadEngChatMessages() {
  if (!engChatJobId) return;
  var res = await api('GET', '/chat/messages?job_id=' + engChatJobId);
  if (!res.success) return;
  var msgs = Array.isArray(res.data) ? res.data : (res.data.messages || []);
  var el = document.getElementById('engChatMessages');
  if (!el) return;
  if (!msgs.length) {
    el.innerHTML = '<div style="text-align:center;padding:20px;color:var(--muted);font-size:13px">No messages yet</div>';
    return;
  }
  var myId = engData ? engData.id : 0;
  el.innerHTML = msgs.map(function(m) {
    var isMe = m.sender_type === 'engineer' && String(m.sender_id) === String(myId);
    return '<div style="display:flex;justify-content:' + (isMe ? 'flex-end' : 'flex-start') + '">' +
      '<div style="max-width:75%;background:' + (isMe ? 'var(--accent)' : '#fff') + ';color:' + (isMe ? '#fff' : 'var(--text)') + ';border-radius:' + (isMe ? '14px 14px 4px 14px' : '14px 14px 14px 4px') + ';padding:10px 14px;font-size:14px;box-shadow:0 1px 3px rgba(0,0,0,.08)">' +
        (m.media_url ? '<img src="' + m.media_url + '" style="max-width:200px;border-radius:8px;display:block;margin-bottom:6px">' : '') +
        (m.message ? '<div>' + m.message + '</div>' : '') +
        '<div style="font-size:10px;opacity:.6;margin-top:4px;text-align:right">' + new Date(m.created_at).toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'}) + '</div>' +
      '</div></div>';
  }).join('');
  el.scrollTop = el.scrollHeight;
}
async function sendEngChat() {
  var inp = document.getElementById('engChatInput');
  var msg = inp ? inp.value.trim() : '';
  if (!msg || !engChatJobId) return;
  inp.value = '';
  var res = await api('POST', '/chat/messages', {job_id: engChatJobId, message: msg});
  if (res.success) loadEngChatMessages();
  else toast(res.message || 'Failed to send');
}

// Stop chat polling safely — called from the back button inside the chat screen
function stopEngChat() {
  if (engChatInterval) { clearInterval(engChatInterval); engChatInterval = null; }
}
